var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......찾았다. 이 망할 자식.","JPN":"……見つけた。このクズ野郎。","ENG":"...Found you. You scumbag.","TWN":"……找到妳了。妳這混蛋。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"......뭐야?","JPN":"……なんだ？","ENG":"...What?","TWN":"……什麼。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"아까 그 쥐새끼들이잖아. 아직 살아 있었나?","JPN":"さっきのネズミじゃないか。まだ生きてたのか？","ENG":"You're the little rats from earlier. You're still alive?","TWN":"這不是剛才那群鼠輩嗎？竟然還活著？"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"조금 전에 너흴 상대한 건 분명 내 직속의 정예 부대원들인데......","JPN":"お前らの相手をさせたのは、直属の精鋭部隊員だぞ……","ENG":"But I sent some of my best troops to deal with you...","TWN":"剛才對付你們的，明明是我直屬的精銳部隊啊……"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"대체 어떻게 살아나온 거지?","JPN":"一体どうやって生き残った？","ENG":"How are you still alive?","TWN":"你們到底是怎麼活下來的？"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"黙れ！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그딴 건 아무래도 좋으니까.","JPN":"そんなことはどうでもいい。","ENG":"I couldn't care less about that.","TWN":"那種事怎麼樣都好。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......에이미가 죽었어. 너 때문에.","JPN":"……エイミーが死んだんだ。あんたのせいで。","ENG":"Amy's dead... And it's because of you!","TWN":"……艾米死了，這都是妳害的。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"......그래서?","JPN":"……それで？","ENG":"So?","TWN":"……所以？"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"쥐새끼 한 마리 죽은 걸 가지고 뭐가 대수라는 거냐?","JPN":"ネズミ一匹死んだからって、それがどうしたって言うんだ？","ENG":"Why are you crying about one dead rat?","TWN":"死了一隻老鼠又有什麼大不了的？"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"설마 그것 때문에 기껏 만들어낸 살 길을 놔두고 여기까지 쫓아온 건 아니겠지?","JPN":"せっかく生き延びれたのに、まさかそのために、わざわざここまで追いかけて来たんじゃないだろうな？","ENG":"Don't tell me you came all the way here to get revenge? I thought I warned you back there...","TWN":"妳該不會是為了這件事，放棄了這麼好的逃跑機會，一路追到這裡來吧？"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그렇게 멍청해 보이진 않는데......","JPN":"そこまでアホには見えなかったけどな……","ENG":"I didn't think you'd be this stupid...","TWN":"妳看起來明明沒有那麼笨啊……"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석은 좋은 사람이었어.","JPN":"あいつはいい奴だった。","ENG":"She was a good person.","TWN":"那傢伙是個好人。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생판 남이라도...... 곤경에 처한 사람을 보면 어떻게든 도우려고 노력하는......","JPN":"赤の他人でも……困り果てた人を見かけたら、何とか助けようと頑張る……","ENG":"She tried her best to help people... Even if they were complete strangers...","TWN":"哪怕對方是個陌生人……只要見到別人有難，她就會盡力地去幫助他們……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 사람이었어.","JPN":"そういう奴だった。","ENG":"That was Amy.","TWN":"她就是這樣的人。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나와는 조금 안 맞긴 했지만...... 어쩌면 바보 같다고 할 수도 있지만......","JPN":"私とは少し合わなかったけど……ちょっとバカなところもあったけど……","ENG":"We didn't always get along... And she was kind of stupid like that...","TWN":"雖然和我有點合不來……大概還是個笨蛋……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_223010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};